const normalized = $json.normalized || {};
const source = $json.source || normalized.source || 'event';
const eventType = $json.event_type || normalized.event_type || 'evento';
const repo = $json.repo || normalized.repo || '';
const actor = $json.actor || normalized.actor || 'system';
const entityType = normalized.entity_type || $json.entity_type || '';
const entityId = normalized.entity_id || $json.entity_id || '';
const prNumber = normalized.pull_request_number || $json.pull_request_number || null;
const cardId = normalized.trello_card_id || $json.trello_card_id || null;
const branch = normalized.branch || $json.branch || null;
const correlationId = $json.correlation_id || normalized.correlation_id || null;
const url = normalized.url || null;

const lines = [];
lines.push('[PetSafe/' + source + '] ' + eventType);
if (actor) lines.push('Actor: ' + actor);
if (repo) lines.push('Repo: ' + repo);
if (entityType || entityId) lines.push('Entity: ' + [entityType, entityId].filter(Boolean).join(' '));
if (prNumber) lines.push('PR: #' + prNumber);
if (cardId) lines.push('Card: ' + cardId);
if (branch) lines.push('Branch: ' + branch);
if (correlationId) lines.push('Correlation: ' + correlationId);
if (url) lines.push(url);

let content = lines.join('\n').slice(0, 1900);

return [{
  json: {
    ...$json,
    outbox_target: 'discord',
    outbox_action: 'notify',
    outbox_idempotency_key: $json.event_id || null,
    outbox_payload: { content }
  }
}];
